1	/**
2	 * Pure statusline renderer - no I/O, no side effects
3	 *
4	 * ARCHITECTURE: Raw data in, formatted string out.
5	 * ALL config decisions happen here, not in data preparation.
6	 */
7	
8	import type { StatuslineConfig } from "./config-types";
9	import {
10		colors,
11		formatCost,
12		formatDuration,
13		formatPath,
14		formatProgressBar,
15		formatResetTime,
16		formatTokens,
17	} from "./formatters";
18	
19	const WEEKLY_HOURS = 168; // 7 days * 24 hours
20	const FIVE_HOUR_MINUTES = 300; // 5 hours * 60 minutes
21	
22	// ─────────────────────────────────────────────────────────────
23	// RAW DATA TYPES - No pre-formatting, just raw values
24	// ─────────────────────────────────────────────────────────────
25	
26	export interface GitChanges {
27		files: number;
28		added: number;
29		deleted: number;
30	}
31	
32	export interface RawGitData {
33		branch: string;
34		dirty: boolean;
35		staged: GitChanges;
36		unstaged: GitChanges;
37	}
38	
39	export interface UsageLimit {
40		utilization: number;
41		resets_at: string | null;
42	}
43	
44	export interface RawStatuslineData {
45		git: RawGitData | null;
46		path: string;
47		modelName: string;
48		cost: number;
49		durationMs: number;
50		contextTokens: number | null;
51		contextPercentage: number | null;
52		usageLimits?: {
53			five_hour: UsageLimit | null;
54			seven_day: UsageLimit | null;
55		};
56		periodCost?: number;
57		todayCost?: number;
58	}
59	
60	// Legacy interface for backwards compatibility
61	export interface StatuslineData {
62		branch: string;
63		dirPath: string;
64		modelName: string;
65		sessionCost: string;
66		sessionDuration: string;
67		contextTokens: number | null;
68		contextPercentage: number | null;
69		usageLimits?: {
70			five_hour: UsageLimit | null;
71			seven_day: UsageLimit | null;
72		};
73		periodCost?: number;
74		todayCost?: number;
75	}
76	
77	// ─────────────────────────────────────────────────────────────
78	// FORMATTING - All config-aware formatting in one place
79	// ─────────────────────────────────────────────────────────────
80	
81	function formatGitPart(
82		git: RawGitData | null,
83		config: StatuslineConfig["git"],
84	): string {
85		if (!git || !config.enabled) return "";
86	
87		const parts: string[] = [];
88	
89		if (config.showBranch) {
90			parts.push(colors.lightGray(git.branch));
91		}
92	
93		if (git.dirty && config.showDirtyIndicator) {
94			// Append to branch name without space
95			if (parts.length > 0) {
96				parts[parts.length - 1] += colors.purple("*");
97			} else {
98				parts.push(colors.purple("*"));
99			}
100		}
101	
102		const changeParts: string[] = [];
103	
104		if (config.showChanges) {
105			const totalAdded = git.staged.added + git.unstaged.added;
106			const totalDeleted = git.staged.deleted + git.unstaged.deleted;
107			if (totalAdded > 0) changeParts.push(colors.green(`+${totalAdded}`));
108			if (totalDeleted > 0) changeParts.push(colors.red(`-${totalDeleted}`));
109		}
110	
111		if (config.showStaged && git.staged.files > 0) {
112			changeParts.push(colors.gray(`~${git.staged.files}`));
113		}
114	
115		if (config.showUnstaged && git.unstaged.files > 0) {
116			changeParts.push(colors.yellow(`~${git.unstaged.files}`));
117		}
118	
119		if (changeParts.length > 0) {
120			parts.push(changeParts.join(" "));
121		}
122	
123		return parts.join(" ");
124	}
125	
126	function formatSessionPart(
127		cost: number,
128		durationMs: number,
129		contextTokens: number | null,
130		contextPercentage: number | null,
131		maxTokens: number,
132		config: StatuslineConfig["session"],
133	): string {
134		// No context data yet - show placeholder
135		if (contextTokens === null || contextPercentage === null) {
136			return `${colors.gray("S:")} ${colors.gray("-")}`;
137		}
138	
139		const items: string[] = [];
140	
141		if (config.cost.enabled) {
142			const formattedCost = formatCost(cost, config.cost.format);
143			items.push(`${colors.gray("$")}${colors.dimWhite(formattedCost)}`);
144		}
145	
146		if (config.tokens.enabled) {
147			const formattedUsed = formatTokens(
148				contextTokens,
149				config.tokens.showDecimals,
150			);
151			if (config.tokens.showMax) {
152				const formattedMax = formatTokens(maxTokens, config.tokens.showDecimals);
153				items.push(`${formattedUsed}${colors.gray("/")}${formattedMax}`);
154			} else {
155				items.push(formattedUsed);
156			}
157		}
158	
159		if (config.percentage.enabled) {
160			const pctParts: string[] = [];
161	
162			if (config.percentage.progressBar.enabled) {
163				pctParts.push(
164					formatProgressBar({
165						percentage: contextPercentage,
166						length: config.percentage.progressBar.length,
167						style: config.percentage.progressBar.style,
168						colorMode: config.percentage.progressBar.color,
169						background: config.percentage.progressBar.background,
170					}),
171				);
172			}
173	
174			if (config.percentage.showValue) {
175				pctParts.push(
176					`${colors.lightGray(contextPercentage.toString())}${colors.gray("%")}`,
177				);
178			}
179	
180			if (pctParts.length > 0) {
181				items.push(pctParts.join(" "));
182			}
183		}
184	
185		if (config.duration.enabled) {
186			items.push(colors.gray(`(${formatDuration(durationMs)})`));
187		}
188	
189		if (items.length === 0) return "";
190	
191		const sep = config.infoSeparator
192			? ` ${colors.gray(config.infoSeparator)} `
193			: " ";
194		return `${colors.gray("S:")} ${items.join(sep)}`;
195	}
196	
197	function formatLimitsPart(
198		fiveHour: UsageLimit | null,
199		periodCost: number,
200		config: StatuslineConfig["limits"],
201	): string {
202		if (!config.enabled || !fiveHour) return "";
203	
204		const parts: string[] = [];
205	
206		if (config.cost.enabled && periodCost > 0) {
207			parts.push(
208				`${colors.gray("$")}${colors.dimWhite(formatCost(periodCost, config.cost.format))}`,
209			);
210		}
211	
212		if (config.percentage.enabled) {
213			if (config.percentage.progressBar.enabled) {
214				parts.push(
215					formatProgressBar({
216						percentage: fiveHour.utilization,
217						length: config.percentage.progressBar.length,
218						style: config.percentage.progressBar.style,
219						colorMode: config.percentage.progressBar.color,
220						background: config.percentage.progressBar.background,
221					}),
222				);
223			}
224	
225			if (config.percentage.showValue) {
226				parts.push(
227					`${colors.lightGray(fiveHour.utilization.toString())}${colors.gray("%")}`,
228				);
229			}
230		}
231	
232		if (config.showPacingDelta && fiveHour.resets_at) {
233			const delta = calculateFiveHourDelta(
234				fiveHour.utilization,
235				fiveHour.resets_at,
236			);
237			parts.push(
238				`${colors.gray("(")}${formatPacingDelta(delta)}${colors.gray(")")}`,
239			);
240		}
241	
242		if (config.showTimeLeft && fiveHour.resets_at) {
243			parts.push(colors.gray(`(${formatResetTime(fiveHour.resets_at)})`));
244		}
245	
246		return parts.length > 0 ? `${colors.gray("L:")} ${parts.join(" ")}` : "";
247	}
248	
249	function shouldShowWeekly(
250		config: StatuslineConfig["weeklyUsage"],
251		fiveHourUtilization: number | null,
252	): boolean {
253		if (config.enabled === true) return true;
254		if (config.enabled === false) return false;
255		if (config.enabled === "90%" && fiveHourUtilization !== null) {
256			return fiveHourUtilization >= 90;
257		}
258		return false;
259	}
260	
261	function calculateWeeklyDelta(
262		utilization: number,
263		resetsAt: string | null,
264	): number {
265		if (!resetsAt) return 0;
266	
267		const resetDate = new Date(resetsAt);
268		const now = new Date();
269		const diffMs = resetDate.getTime() - now.getTime();
270		const hoursRemaining = Math.max(0, diffMs / 3600000);
271		const timeElapsedPercent =
272			((WEEKLY_HOURS - hoursRemaining) / WEEKLY_HOURS) * 100;
273	
274		return utilization - timeElapsedPercent;
275	}
276	
277	function formatPacingDelta(delta: number): string {
278		const sign = delta >= 0 ? "+" : "";
279		const value = `${sign}${delta.toFixed(1)}%`;
280	
281		if (delta > 5) return colors.green(value);
282		if (delta > 0) return colors.lightGray(value);
283		if (delta > -10) return colors.yellow(value);
284		return colors.red(value);
285	}
286	
287	function calculateFiveHourDelta(
288		utilization: number,
289		resetsAt: string | null,
290	): number {
291		if (!resetsAt) return 0;
292	
293		const resetDate = new Date(resetsAt);
294		const now = new Date();
295		const diffMs = resetDate.getTime() - now.getTime();
296		const minutesRemaining = Math.max(0, diffMs / 60000);
297		const timeElapsedPercent =
298			((FIVE_HOUR_MINUTES - minutesRemaining) / FIVE_HOUR_MINUTES) * 100;
299	
300		return utilization - timeElapsedPercent;
301	}
302	
303	function formatWeeklyPart(
304		sevenDay: UsageLimit | null,
305		fiveHourUtilization: number | null,
306		periodCost: number,
307		config: StatuslineConfig["weeklyUsage"],
308	): string {
309		if (!shouldShowWeekly(config, fiveHourUtilization) || !sevenDay) return "";
310	
311		const parts: string[] = [];
312	
313		if (config.cost.enabled && periodCost > 0) {
314			parts.push(
315				`${colors.gray("$")}${colors.dimWhite(formatCost(periodCost, config.cost.format))}`,
316			);
317		}
318	
319		if (config.percentage.enabled) {
320			if (config.percentage.progressBar.enabled) {
